create extension if not exists pgcrypto;
create table if not exists users(id uuid primary key default gen_random_uuid(),name varchar(100) not null,email varchar(255) unique not null,password_hash text not null,role varchar(30) not null default 'user',is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists devices(id uuid primary key default gen_random_uuid(),user_id uuid not null references users(id) on delete cascade,name varchar(100) not null,type varchar(40) not null,os varchar(80),status varchar(20) not null default 'offline',permissions jsonb not null default '{}'::jsonb,ip_address inet,device_token text unique,last_seen_at timestamptz,created_at timestamptz not null default now());
create table if not exists conversations(id uuid primary key default gen_random_uuid(),user_id uuid not null references users(id) on delete cascade,title varchar(180) not null default 'New conversation',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists messages(id uuid primary key default gen_random_uuid(),conversation_id uuid not null references conversations(id) on delete cascade,user_id uuid not null references users(id) on delete cascade,device_id uuid references devices(id) on delete set null,role varchar(20) not null check(role in('system','user','assistant','tool')),content text not null,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists memories(id uuid primary key default gen_random_uuid(),user_id uuid not null references users(id) on delete cascade,category varchar(50) not null default 'general',key varchar(120) not null,value jsonb not null,importance smallint not null default 3 check(importance between 1 and 5),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists notes(id uuid primary key default gen_random_uuid(),user_id uuid not null references users(id) on delete cascade,title varchar(160) not null,content text not null default '',tags text[] not null default '{}',priority varchar(20) not null default 'normal',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists tasks(id uuid primary key default gen_random_uuid(),user_id uuid not null references users(id) on delete cascade,title varchar(160) not null,description text not null default '',due_at timestamptz,priority varchar(20) not null default 'normal',status varchar(30) not null default 'pending',reminder_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists agent_connections(id uuid primary key default gen_random_uuid(),user_id uuid not null references users(id) on delete cascade,device_id uuid unique not null references devices(id) on delete cascade,status varchar(20) not null default 'offline',last_heartbeat_at timestamptz,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists pending_actions(id uuid primary key default gen_random_uuid(),user_id uuid not null references users(id) on delete cascade,device_id uuid not null references devices(id) on delete cascade,action_type varchar(60) not null,payload jsonb not null default '{}'::jsonb,requires_confirmation boolean not null default false,status varchar(20) not null default 'pending',result jsonb,error_message text,created_at timestamptz not null default now(),completed_at timestamptz);
create table if not exists activity_logs(id bigserial primary key,user_id uuid references users(id) on delete set null,action varchar(120) not null,entity_type varchar(80),entity_id uuid,ip_address inet,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists api_usage(id bigserial primary key,user_id uuid references users(id) on delete set null,provider varchar(50),model varchar(100),endpoint varchar(150),input_tokens int not null default 0,output_tokens int not null default 0,latency_ms int,success boolean not null,error_message text,created_at timestamptz not null default now());
create index if not exists idx_messages_conversation on messages(conversation_id,created_at);create index if not exists idx_memories_user on memories(user_id,updated_at desc);create index if not exists idx_tasks_user_due on tasks(user_id,due_at);create index if not exists idx_logs_user_created on activity_logs(user_id,created_at desc);create index if not exists idx_usage_user_created on api_usage(user_id,created_at desc);
